+        let focus = InputEvent::Focus(FocusInput { focused: true });
+        let out: Vec<InputEvent> = state.rewrite(focus.clone()).into_events().collect();
+        assert_eq!(out, vec![focus]);
+        assert!(state.is_active());
+    }
